    background-image: url('https://files.catbox.moe/5fcrb2.png');
}

/* 高级格式图标 */
#advanced-formatting-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/a9vqhy.png');
}

/* 世界信息图标 */
#WI-SP-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/5fcrb2.png');
}

/* 用户设置图标 */
#user-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/a9vqhy.png');
}

/* Logo图标 */
#logo_block .drawer-icon::before {
    background-image: url('https://files.catbox.moe/5fcrb2.png');
}

/* 扩展设置图标 */
#extensions-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/a9vqhy.png');
}

/* 角色管理图标 */
#persona-management-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/5fcrb2.png');
}



/* 右侧导航图标 */
#rightNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/a9vqhy.png');
}








/* 特殊按钮样式 */
/* 菜单按钮 */
.fa-bars {
  background: url('https://files.catbox.moe/bwi09d.png') center/contain no-repeat !important;
  width: 36px !important;
  height: 36px !important;
  filter: drop-shadow(0 0 2px rgba(139, 69, 19, 0.3));
}

/* 扩展按钮 */
#extensionsMenuButton {
  background: url('https://files.catbox.moe/xnf7j6.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-top: 2px !important;
}

/* 发送按钮 */
.fa-paper-plane {
  background: url('https://files.catbox.moe/xgupds.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-left: 5px !important;
}

/* 隐藏特殊按钮的默认图标 */
/* Font Awesome类图标 */
.fa-bars::before,           /* 菜单按钮 */
